// YARDIMCI FONKSIYONLAR
// ============================================================

/**
 * Belirli bir ile ait tum ilceleri dondurur
 * @param plaka - Il plaka kodu (1-81)
 */
export function getDistrictsByCity(plaka: number): District[] {
  return districts.filter(d => d.plaka === plaka);
}

/**
 * ID ile ilce arar
 * @param id - Ilce ID'si (ornek: '34-kadikoy')
 */
export function findDistrict(id: string): District | undefined {
  return districts.find(d => d.id === id);
}

/**
 * Turkce karakterleri ASCII'ye donusturur (arama icin)
 */
function turkishNormalize(str: string): string {
  return str
    .replace(/İ/g, 'I')
    .replace(/Ğ/g, 'G')
    .replace(/Ü/g, 'U')
    .replace(/Ş/g, 'S')
    .replace(/Ö/g, 'O')
    .replace(/Ç/g, 'C')
    .replace(/ı/g, 'i')
    .replace(/ğ/g, 'g')
    .replace(/ü/g, 'u')
    .replace(/ş/g, 's')
    .replace(/ö/g, 'o')
    .replace(/ç/g, 'c')
    .toLowerCase();
}

/**
 * Ilce veya il adina gore arama yapar
 * Turkce karakter destegiyle: "kadıköy" yazinca "Kadikoy" bulunur
 * @param query - Aranacak metin
 */
export function searchDistricts(query: string): District[] {
  const q = turkishNormalize(query);
  return districts.filter(d =>
    d.ilce.toLowerCase().includes(q) ||
    d.il.toLowerCase().includes(q) ||
    d.id.includes(q)
  );
}
